const choice = $json.range;  // "metasploitable2" | "juiceshop" | "goad"
const items = [];

// Example template IDs – replace with your actual Proxmox template IDs
const TEMPLATES = {
  metasploitable2: 10000,
  juiceshop: 10001,
  goad_dc: 20000,
  goad_member: 20001,
  goad_client: 20002,
};

if (choice === '$input.first().json["VM Options"]') {
  // Loop for Metasploitable 2 (e.g. 3 copies)
  for (let i = 1; i <= 3; i++) {
    items.push({
      json: {
        type: 'metasploitable2',
        index: i,
        templateId: TEMPLATES.metasploitable2,
        name: `meta2-${i}`,
      },
    });
  }

} else if (choice === 'juiceshop') {
  // Loop for OWASP Juice Shop (e.g. 1 copy)
  for (let i = 1; i <= 1; i++) {
    items.push({
      json: {
        type: 'juiceshop',
        index: i,
        templateId: TEMPLATES.juiceshop,
        name: `juice-${i}`,
      },
    });
  }

} else if (choice === 'goad') {
  // GOAD = different VMs/roles instead of simple count
  const goadVms = [
    { role: 'dc',      templateId: TEMPLATES.goad_dc,     name: 'goad-dc' },
    { role: 'member',  templateId: TEMPLATES.goad_member, name: 'goad-member' },
    { role: 'client',  templateId: TEMPLATES.goad_client, name: 'goad-client' },
  ];

  for (const vm of goadVms) {
    items.push({
      json: {
        type: 'goad',
        role: vm.role,
        templateId: vm.templateId,
        name: vm.name,
      },
    });
  }

} else {
  // Fallback if somehow nothing matched
  items.push({
    json: {
      type: 'unknown',
      range: choice,
    },
  });
}

return items;

// Combine all possible stdout fields
const output = $json.stdout || $json.data || "";

// Match ALL integers in the output
const matches = output.match(/\b\d+\b/g);

if (!matches || matches.length === 0) {
  return [{
    json: {
      error: "No numbers found in output",
      raw: output,
    },
  }];
}

// Get the LAST number — this is the VMID
const vmid = parseInt(matches[matches.length - 1], 10);

return [{
  json: {
    vmid,
  },
}];

// Get SSH output (stdout) from previous node
const output = $json.stdout || "";

// Regex to capture MAC address after '=' and before ','
const macMatch = output.match(/=([A-Fa-f0-9:]{17})/);

if (!macMatch) {
  return [
    {
      json: {
        error: "MAC address not found in qm config output",
        raw: output,
      },
    },
  ];
}

const mac = macMatch[1].toUpperCase();

// Return MAC formatted for next node
return [
  {
    json: {
      mac,
    },
  },
];

// Get all incoming items
const items = $input.all();

let targetMac = null;
let leases = null;

// Find the MAC and the DHCP rows in the inputs
for (const item of items) {
  if (item.json.mac && !targetMac) {
    targetMac = String(item.json.mac).trim().toLowerCase();
  }
  if (Array.isArray(item.json.rows) && !leases) {
    leases = item.json.rows;
  }
}

if (!targetMac || !leases) {
  return [{
    json: {
      error: 'Missing MAC or DHCP rows in input',
      input: items.map(i => i.json),
    },
  }];
}

// Find the lease whose mac matches targetMac
const lease = leases.find(l => String(l.mac || '').toLowerCase() === targetMac);

if (!lease) {
  return [{
    json: {
      error: `No lease found for MAC ${targetMac}`,
      leasesChecked: leases.length,
    },
  }];
}

// Return the whole lease object as json
return [{
  json: lease,
}];
